#include<bits/stdc++.h>
using namespace std;
int nextt[1000001],n,m;
    string a,b;
void nexts(){
    nextt[0]=0;
    nextt[1]=0;
    for(int i=0,j=2;j<=m;j++){

        while(b[i]!=b[j-1]) {
            if(i==0) {
                i=-1;
                break;
            }
            i=nextt[i];
        }
        i++;
        nextt[j]=i;
       // cout<<nextt[j]<<' ';
    }
    //cout<<"\n";
}
void KMP(){
    int i=0,j=0;
    while(i<n){

        if(a[i]==b[j]){
            i++;
            j++;
        }else if(j>0){
            j=nextt[j];
        }else{
            i++;
        }//cout<<i<<" "<<j<<'\n';
        if(j==m){
            cout<<i-j+1<<"\n";
            j=nextt[j];
        }
    }
}
int main(){

    cin>>a>>b;

    m=b.size();
    n=a.size();
    nexts();
    KMP();
    for(int i=1;i<=m;i++) cout<<nextt[i]<<" ";
    return 0;
}
